74	const COMPONENT_TYPES = ["rune", "moonstone"];
75	const BLOCK_OF_THREE_BASE = 60;
76	
77	function countByType(items: Array<Item>): Record<string, number> {
78	  const counts: Record<string, number> = {};
79	  for (const item of items) {
80	    counts[item.type] = (counts[item.type] ?? 0) + 1;
81	  }
82	  return counts;
83	}
