85	function isLoyalCustomer(customer: Customer | undefined): boolean {
86	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
87	}
88	
89	function quoteItems(items: Array<Item>): { itemsPremium: number; sumOfBases: number } {
90	  const counts = countByType(items);
91	  let itemsPremium = 0;
92	  let sumOfBases = 0;
93	  const bundledTypes = new Set<string>();
94	
95	  for (const componentType of COMPONENT_TYPES) {
96	    if (counts[componentType] === 3) {
97	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
98	      sumOfBases += BLOCK_OF_THREE_BASE;
99	      bundledTypes.add(componentType);
100	    }
101	  }
102	
103	  for (const item of items) {
104	    if (bundledTypes.has(item.type)) continue;
105	    itemsPremium += quoteItem(item);
106	    sumOfBases += getBasePremium(item.type);
107	  }
108	
109	  return { itemsPremium, sumOfBases };
110	}
