112	type Policy = { items: Array<Item>; capRemaining: number };
113	
114	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
115	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
116	
117	function computeDamagePayout(damage: Damage, policy: Policy | undefined): number {
118	  const item = policy?.items.find((i) => i.type === damage.itemType);
119	  const reimbursableAmount = hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD)
120	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
121	    : damage.amount;
122	  return Math.max(0, reimbursableAmount - DEDUCTIBLE_PER_DAMAGE);
123	}
124	
125	function computePayout(incident: Incident | undefined, policy: Policy | undefined): number {
126	  const damages = incident?.damages ?? [];
127	  return damages.reduce((total, damage) => total + computeDamagePayout(damage, policy), 0);
128	}
129	
130	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
131	
132	function handleClaim(step: Step, policies: Map<number, Policy>): StepResult {
133	  const policy = policies.get(step.policy ?? 0);
134	  const desired = Math.floor(computePayout(step.incident, policy));
135	  const capRemaining = policy?.capRemaining ?? Infinity;
136	  const actualPayout = Math.min(desired, capRemaining);
137	  const newCapRemaining = capRemaining - actualPayout;
138	  if (policy) policy.capRemaining = newCapRemaining;
139	  return { payout: actualPayout, remainingCap: newCapRemaining };
140	}
141	
142	function handleQuote(
143	  step: Step,
144	  stepIndex: number,
145	  customer: Customer | undefined,
146	  policies: Map<number, Policy>,
147	): StepResult {
148	  const items = step.items ?? [];
149	  policies.set(stepIndex, {
150	    items,
151	    capRemaining: CAP_MULTIPLIER * computeInsuranceSum(items),
152	  });
153	  const { itemsPremium, sumOfBases } = quoteItems(items);
154	  const loyaltyDiscount = isLoyalCustomer(customer) ? sumOfBases * LOYALTY_DISCOUNT_RATE : 0;
155	  const followUpDiscount = stepIndex >= 1 ? sumOfBases * FOLLOWUP_DISCOUNT_RATE : 0;
156	  const premium = Math.ceil(itemsPremium - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
157	  return { premium };
158	}
159	
160	export function processScenario(scenario: unknown): { results: Array<StepResult> } {
161	  const { customer, steps } = scenario as Scenario;
162	  const policies = new Map<number, Policy>();
163	  const results = steps.map((step, stepIndex) =>
164	    step.op === "claim"
165	      ? handleClaim(step, policies)
166	      : handleQuote(step, stepIndex, customer, policies),
167	  );
168	  return { results };
169	}
